{
  "provider": "linkedin",
  "apiHost": "api.linkedin.com",
  "basePath": "/v2",
  "notes": "LinkedIn uses both /v2 (legacy) and /rest (newer versioned APIs). The /rest endpoints require Linkedin-Version header in YYYYMM format. Some scopes (r_member_social, r_organization_social, w_organization_social, rw_organization_admin) require Marketing Developer Platform or Community Management API access.",
  "scopeMap": [
    {
      "method": "GET",
      "pathPattern": "/v2/me",
      "sufficientScopes": ["r_liteprofile"],
      "description": "Get the authenticated member's basic profile (legacy endpoint)"
    },
    {
      "method": "GET",
      "pathPattern": "/v2/userinfo",
      "sufficientScopes": ["openid", "profile"],
      "description": "Get the authenticated member's profile via OpenID Connect (current)"
    },
    {
      "method": "GET",
      "pathPattern": "/v2/me?projection=*",
      "sufficientScopes": ["r_basicprofile"],
      "description": "Get the authenticated member's full basic profile fields"
    },
    {
      "method": "GET",
      "pathPattern": "/v2/emailAddress?q=members&projection=(elements*(handle~))",
      "sufficientScopes": ["r_emailaddress"],
      "description": "Get the authenticated member's primary email address"
    },
    {
      "method": "GET",
      "pathPattern": "/v2/connections",
      "sufficientScopes": ["r_1st_connections_size"],
      "description": "Get the authenticated member's 1st-degree connection count"
    },
    {
      "method": "POST",
      "pathPattern": "/rest/posts",
      "sufficientScopes": ["w_member_social"],
      "description": "Create a post on behalf of the authenticated member"
    },
    {
      "method": "POST",
      "pathPattern": "/v2/ugcPosts",
      "sufficientScopes": ["w_member_social"],
      "description": "Create a UGC post on behalf of the authenticated member (legacy)"
    },
    {
      "method": "GET",
      "pathPattern": "/rest/posts/*",
      "sufficientScopes": ["r_member_social"],
      "description": "Get a specific post by URN for the authenticated member"
    },
    {
      "method": "GET",
      "pathPattern": "/rest/posts?q=author&author=urn:li:person:*",
      "sufficientScopes": ["r_member_social"],
      "description": "Find posts by a member author"
    },
    {
      "method": "POST",
      "pathPattern": "/rest/posts/*",
      "sufficientScopes": ["w_member_social"],
      "description": "Update a post authored by the authenticated member (PARTIAL_UPDATE)"
    },
    {
      "method": "DELETE",
      "pathPattern": "/rest/posts/*",
      "sufficientScopes": ["w_member_social"],
      "description": "Delete a post authored by the authenticated member"
    },
    {
      "method": "POST",
      "pathPattern": "/rest/posts?author=urn:li:organization:*",
      "sufficientScopes": ["w_organization_social"],
      "description": "Create a post on behalf of an organization"
    },
    {
      "method": "GET",
      "pathPattern": "/rest/posts?q=author&author=urn:li:organization:*",
      "sufficientScopes": ["r_organization_social"],
      "description": "Find posts by an organization author"
    },
    {
      "method": "DELETE",
      "pathPattern": "/rest/posts/*",
      "sufficientScopes": ["w_organization_social"],
      "description": "Delete a post authored by an organization"
    },
    {
      "method": "GET",
      "pathPattern": "/v2/ugcPosts/*",
      "sufficientScopes": ["r_member_social"],
      "description": "Get a specific UGC post by URN (legacy)"
    },
    {
      "method": "DELETE",
      "pathPattern": "/v2/ugcPosts/*",
      "sufficientScopes": ["w_member_social"],
      "description": "Delete a UGC post by URN (legacy)"
    },
    {
      "method": "GET",
      "pathPattern": "/v2/shares?q=owners&owners=urn:li:organization:*",
      "sufficientScopes": ["r_organization_social"],
      "description": "Get shares owned by an organization (legacy)"
    },
    {
      "method": "POST",
      "pathPattern": "/v2/shares",
      "sufficientScopes": ["w_member_social"],
      "description": "Create a share on behalf of the authenticated member (legacy)"
    },
    {
      "method": "GET",
      "pathPattern": "/rest/socialActions/*/comments",
      "sufficientScopes": ["r_member_social"],
      "description": "List comments on a post (member context)"
    },
    {
      "method": "POST",
      "pathPattern": "/rest/socialActions/*/comments",
      "sufficientScopes": ["w_member_social"],
      "description": "Create a comment on a post as the authenticated member"
    },
    {
      "method": "DELETE",
      "pathPattern": "/rest/socialActions/*/comments/*",
      "sufficientScopes": ["w_member_social"],
      "description": "Delete a comment by the authenticated member"
    },
    {
      "method": "GET",
      "pathPattern": "/rest/socialActions/*/comments",
      "sufficientScopes": ["r_organization_social"],
      "description": "List comments on a post (organization context)"
    },
    {
      "method": "POST",
      "pathPattern": "/rest/socialActions/*/comments",
      "sufficientScopes": ["w_organization_social"],
      "description": "Create a comment on a post as an organization"
    },
    {
      "method": "DELETE",
      "pathPattern": "/rest/socialActions/*/comments/*",
      "sufficientScopes": ["w_organization_social"],
      "description": "Delete a comment by an organization"
    },
    {
      "method": "GET",
      "pathPattern": "/rest/socialActions/*/likes",
      "sufficientScopes": ["r_member_social"],
      "description": "List likes/reactions on a post (member context)"
    },
    {
      "method": "POST",
      "pathPattern": "/rest/socialActions/*/likes",
      "sufficientScopes": ["w_member_social"],
      "description": "Like or react to a post as the authenticated member"
    },
    {
      "method": "DELETE",
      "pathPattern": "/rest/socialActions/*/likes/*",
      "sufficientScopes": ["w_member_social"],
      "description": "Remove a like/reaction by the authenticated member"
    },
    {
      "method": "GET",
      "pathPattern": "/rest/socialActions/*/likes",
      "sufficientScopes": ["r_organization_social"],
      "description": "List likes/reactions on a post (organization context)"
    },
    {
      "method": "POST",
      "pathPattern": "/rest/socialActions/*/likes",
      "sufficientScopes": ["w_organization_social"],
      "description": "Like or react to a post as an organization"
    },
    {
      "method": "DELETE",
      "pathPattern": "/rest/socialActions/*/likes/*",
      "sufficientScopes": ["w_organization_social"],
      "description": "Remove a like/reaction by an organization"
    },
    {
      "method": "GET",
      "pathPattern": "/v2/organizations/*",
      "sufficientScopes": ["r_organization_social"],
      "description": "Get an organization's profile by ID"
    },
    {
      "method": "GET",
      "pathPattern": "/v2/organizationalEntityAcls?q=roleAssignee",
      "sufficientScopes": ["rw_organization_admin"],
      "description": "Find organizations for which the member has admin access"
    },
    {
      "method": "GET",
      "pathPattern": "/v2/organizationPageStatistics?q=organization&organization=*",
      "sufficientScopes": ["r_organization_social", "rw_organization_admin"],
      "description": "Get page statistics for an organization"
    },
    {
      "method": "GET",
      "pathPattern": "/v2/organizationalEntityFollowerStatistics?q=organizationalEntity&organizationalEntity=*",
      "sufficientScopes": ["r_organization_social", "rw_organization_admin"],
      "description": "Get follower statistics for an organization"
    },
    {
      "method": "GET",
      "pathPattern": "/v2/organizationalEntityShareStatistics?q=organizationalEntity&organizationalEntity=*",
      "sufficientScopes": ["r_organization_social", "rw_organization_admin"],
      "description": "Get share/post statistics for an organization"
    },
    {
      "method": "GET",
      "pathPattern": "/rest/organizationFollowerCount?q=organizationalEntity&organizationalEntity=*",
      "sufficientScopes": ["r_organization_followers"],
      "description": "Get follower count for an organization"
    },
    {
      "method": "POST",
      "pathPattern": "/rest/images?action=initializeUpload",
      "sufficientScopes": ["w_member_social"],
      "description": "Initialize an image upload for member posts"
    },
    {
      "method": "POST",
      "pathPattern": "/rest/images?action=initializeUpload",
      "sufficientScopes": ["w_organization_social"],
      "description": "Initialize an image upload for organization posts"
    },
    {
      "method": "GET",
      "pathPattern": "/rest/images/*",
      "sufficientScopes": ["r_member_social"],
      "description": "Get image metadata by URN"
    },
    {
      "method": "POST",
      "pathPattern": "/rest/videos?action=initializeUpload",
      "sufficientScopes": ["w_member_social"],
      "description": "Initialize a video upload for member posts"
    },
    {
      "method": "POST",
      "pathPattern": "/rest/videos?action=initializeUpload",
      "sufficientScopes": ["w_organization_social"],
      "description": "Initialize a video upload for organization posts"
    },
    {
      "method": "GET",
      "pathPattern": "/rest/videos/*",
      "sufficientScopes": ["r_member_social"],
      "description": "Get video metadata by URN"
    },
    {
      "method": "POST",
      "pathPattern": "/rest/documents?action=initializeUpload",
      "sufficientScopes": ["w_member_social"],
      "description": "Initialize a document upload for member posts"
    },
    {
      "method": "POST",
      "pathPattern": "/rest/documents?action=initializeUpload",
      "sufficientScopes": ["w_organization_social"],
      "description": "Initialize a document upload for organization posts"
    },
    {
      "method": "GET",
      "pathPattern": "/rest/memberCreatorVideoAnalytics",
      "sufficientScopes": ["r_member_social"],
      "description": "Get video analytics for member-created videos"
    },
    {
      "method": "GET",
      "pathPattern": "/rest/socialMetadata/*",
      "sufficientScopes": ["r_member_social"],
      "description": "Get social metadata (like counts, comment counts) for a post"
    },
    {
      "method": "POST",
      "pathPattern": "/rest/socialMetadata/*",
      "sufficientScopes": ["w_member_social"],
      "description": "Update social metadata (enable/disable comments) on a member post"
    },
    {
      "method": "GET",
      "pathPattern": "/v2/adAnalyticsV2?q=analytics",
      "sufficientScopes": ["r_ads_reporting"],
      "description": "Get ad analytics and reporting data"
    },
    {
      "method": "GET",
      "pathPattern": "/v2/adCampaignsV2/*",
      "sufficientScopes": ["r_ads"],
      "description": "Get ad campaign details"
    },
    {
      "method": "GET",
      "pathPattern": "/v2/adCampaignsV2?q=search",
      "sufficientScopes": ["r_ads"],
      "description": "Search ad campaigns"
    },
    {
      "method": "POST",
      "pathPattern": "/v2/adCampaignsV2",
      "sufficientScopes": ["rw_ads"],
      "description": "Create an ad campaign"
    },
    {
      "method": "POST",
      "pathPattern": "/v2/adCampaignsV2/*",
      "sufficientScopes": ["rw_ads"],
      "description": "Update an ad campaign"
    },
    {
      "method": "GET",
      "pathPattern": "/v2/adAccountsV2/*",
      "sufficientScopes": ["r_ads"],
      "description": "Get ad account details"
    },
    {
      "method": "GET",
      "pathPattern": "/v2/adCreativesV2?q=search",
      "sufficientScopes": ["r_ads"],
      "description": "Search ad creatives"
    },
    {
      "method": "POST",
      "pathPattern": "/v2/adCreativesV2",
      "sufficientScopes": ["rw_ads"],
      "description": "Create an ad creative"
    },
    {
      "method": "POST",
      "pathPattern": "/v2/adCreativesV2/*",
      "sufficientScopes": ["rw_ads"],
      "description": "Update an ad creative"
    },
    {
      "method": "GET",
      "pathPattern": "/v2/adCampaignGroupsV2/*",
      "sufficientScopes": ["r_ads"],
      "description": "Get ad campaign group details"
    },
    {
      "method": "POST",
      "pathPattern": "/v2/adCampaignGroupsV2",
      "sufficientScopes": ["rw_ads"],
      "description": "Create an ad campaign group"
    },
    {
      "method": "POST",
      "pathPattern": "/v2/adCampaignGroupsV2/*",
      "sufficientScopes": ["rw_ads"],
      "description": "Update an ad campaign group"
    }
  ],
  "allScopes": [
    "openid",
    "profile",
    "email",
    "w_member_social",
    "r_liteprofile",
    "r_emailaddress",
    "r_basicprofile",
    "r_member_social",
    "r_organization_social",
    "w_organization_social",
    "rw_organization_admin",
    "r_ads",
    "r_ads_reporting",
    "rw_ads",
    "r_1st_connections_size",
    "r_organization_followers"
  ]
}

{
  "provider": "instagram",
  "apiHost": "graph.instagram.com",
  "alternateApiHost": "graph.facebook.com",
  "basePath": "/",
  "notes": "Instagram Graph API uses Facebook Graph API infrastructure. graph.instagram.com is used with Instagram Login (Business Login), graph.facebook.com with Facebook Login. The Basic Display API was sunset on Dec 4 2024. Only Business and Creator accounts are supported. Path segments with {id} patterns use * as wildcard.",
  "scopeMap": [
    {
      "method": "GET",
      "pathPattern": "/me",
      "sufficientScopes": ["instagram_basic"],
      "description": "Get the authenticated user's profile (username, account_type, media_count, etc.)"
    },
    {
      "method": "GET",
      "pathPattern": "/*",
      "sufficientScopes": ["instagram_basic"],
      "description": "Get a specific user profile by user ID"
    },
    {
      "method": "GET",
      "pathPattern": "/me/media",
      "sufficientScopes": ["instagram_basic"],
      "description": "List all media objects for the authenticated user"
    },
    {
      "method": "GET",
      "pathPattern": "/*/media",
      "sufficientScopes": ["instagram_basic"],
      "description": "List all media objects for a specific user"
    },
    {
      "method": "GET",
      "pathPattern": "/*",
      "sufficientScopes": ["instagram_basic"],
      "description": "Get a specific media object by media ID (fields: id, caption, media_type, media_url, timestamp, etc.)"
    },
    {
      "method": "GET",
      "pathPattern": "/*/children",
      "sufficientScopes": ["instagram_basic"],
      "description": "Get children media of a carousel album"
    },
    {
      "method": "POST",
      "pathPattern": "/*/media",
      "sufficientScopes": ["instagram_content_publish"],
      "description": "Create a media container for publishing (image, video, carousel, reel)"
    },
    {
      "method": "POST",
      "pathPattern": "/*/media_publish",
      "sufficientScopes": ["instagram_content_publish"],
      "description": "Publish a media container (after container status is FINISHED)"
    },
    {
      "method": "GET",
      "pathPattern": "/*/content_publishing_limit",
      "sufficientScopes": ["instagram_content_publish"],
      "description": "Check the content publishing rate limit for a user"
    },
    {
      "method": "GET",
      "pathPattern": "/*/comments",
      "sufficientScopes": ["instagram_basic"],
      "description": "List comments on a media object"
    },
    {
      "method": "POST",
      "pathPattern": "/*/comments",
      "sufficientScopes": ["instagram_manage_comments"],
      "description": "Post a comment on a media object"
    },
    {
      "method": "POST",
      "pathPattern": "/*/replies",
      "sufficientScopes": ["instagram_manage_comments"],
      "description": "Reply to a specific comment"
    },
    {
      "method": "GET",
      "pathPattern": "/*/replies",
      "sufficientScopes": ["instagram_basic"],
      "description": "Get replies to a specific comment"
    },
    {
      "method": "DELETE",
      "pathPattern": "/*",
      "sufficientScopes": ["instagram_manage_comments"],
      "description": "Delete a comment by comment ID"
    },
    {
      "method": "POST",
      "pathPattern": "/*",
      "sufficientScopes": ["instagram_manage_comments"],
      "description": "Hide or unhide a comment (set hidden=true/false)"
    },
    {
      "method": "GET",
      "pathPattern": "/*/insights",
      "sufficientScopes": ["instagram_manage_insights"],
      "description": "Get insights for a user (impressions, reach, follower demographics, etc.)"
    },
    {
      "method": "GET",
      "pathPattern": "/*/insights",
      "sufficientScopes": ["instagram_manage_insights"],
      "description": "Get insights for a specific media object (impressions, reach, engagement, saves)"
    },
    {
      "method": "GET",
      "pathPattern": "/*/stories",
      "sufficientScopes": ["instagram_basic"],
      "description": "Get stories for a user"
    },
    {
      "method": "GET",
      "pathPattern": "/*/live_media",
      "sufficientScopes": ["instagram_basic"],
      "description": "Get live video media for a user"
    },
    {
      "method": "GET",
      "pathPattern": "/ig_hashtag_search",
      "sufficientScopes": ["instagram_basic", "pages_read_engagement"],
      "description": "Search for a hashtag ID by name (Facebook Login only)"
    },
    {
      "method": "GET",
      "pathPattern": "/*/top_media",
      "sufficientScopes": ["instagram_basic", "pages_read_engagement"],
      "description": "Get top media for a hashtag"
    },
    {
      "method": "GET",
      "pathPattern": "/*/recent_media",
      "sufficientScopes": ["instagram_basic", "pages_read_engagement"],
      "description": "Get recent media for a hashtag"
    },
    {
      "method": "GET",
      "pathPattern": "/*/recently_searched_hashtags",
      "sufficientScopes": ["instagram_basic", "pages_read_engagement"],
      "description": "Get recently searched hashtags for a user"
    },
    {
      "method": "GET",
      "pathPattern": "/*/tags",
      "sufficientScopes": ["instagram_basic"],
      "description": "Get media in which the user has been tagged (mentions)"
    },
    {
      "method": "GET",
      "pathPattern": "/*/mentioned_media",
      "sufficientScopes": ["instagram_basic"],
      "description": "Get media where the user was mentioned in a caption or comment"
    },
    {
      "method": "GET",
      "pathPattern": "/*/mentioned_comment",
      "sufficientScopes": ["instagram_basic"],
      "description": "Get comments where the user was mentioned"
    },
    {
      "method": "GET",
      "pathPattern": "/*/media_product_tags",
      "sufficientScopes": ["instagram_shopping_tag_products"],
      "description": "Get product tags on a media object"
    },
    {
      "method": "POST",
      "pathPattern": "/*/media_product_tags",
      "sufficientScopes": ["instagram_shopping_tag_products"],
      "description": "Create or update product tags on a media object"
    },
    {
      "method": "DELETE",
      "pathPattern": "/*/media_product_tags",
      "sufficientScopes": ["instagram_shopping_tag_products"],
      "description": "Delete product tags from a media object"
    },
    {
      "method": "GET",
      "pathPattern": "/*/product_catalog",
      "sufficientScopes": ["instagram_shopping_tag_products"],
      "description": "Get the product catalog associated with the user"
    },
    {
      "method": "GET",
      "pathPattern": "/*/available_catalogs",
      "sufficientScopes": ["instagram_shopping_tag_products"],
      "description": "Get available product catalogs for the user"
    },
    {
      "method": "GET",
      "pathPattern": "/*/catalog_product_search",
      "sufficientScopes": ["instagram_shopping_tag_products"],
      "description": "Search products within a catalog for tagging"
    },
    {
      "method": "GET",
      "pathPattern": "/me/accounts",
      "sufficientScopes": ["pages_show_list"],
      "description": "List Facebook Pages the user manages (needed to find linked Instagram accounts)"
    },
    {
      "method": "GET",
      "pathPattern": "/*/instagram_accounts",
      "sufficientScopes": ["pages_show_list", "instagram_basic"],
      "description": "Get Instagram Business Account linked to a Facebook Page"
    },
    {
      "method": "GET",
      "pathPattern": "/*?fields=instagram_business_account",
      "sufficientScopes": ["pages_show_list", "instagram_basic"],
      "description": "Get the Instagram Business Account ID linked to a Facebook Page"
    }
  ],
  "allScopes": [
    "instagram_basic",
    "instagram_content_publish",
    "instagram_manage_comments",
    "instagram_manage_insights",
    "instagram_shopping_tag_products",
    "pages_show_list",
    "pages_read_engagement",
    "business_management"
  ]
}

{
  "provider": "stripe",
  "apiHost": "api.stripe.com",
  "basePath": "/v1",
  "notes": "Stripe traditionally uses API keys (secret/restricted keys) rather than OAuth scopes. These semantic scopes are defined for proxy-based policy enforcement. Restricted keys in Stripe can be configured with per-resource read/write permissions, which these scopes mirror. The :id path segments are represented as *.",
  "scopeMap": [
    {
      "method": "GET",
      "pathPattern": "/v1/charges",
      "sufficientScopes": ["charges.read"],
      "description": "List all charges"
    },
    {
      "method": "GET",
      "pathPattern": "/v1/charges/*",
      "sufficientScopes": ["charges.read"],
      "description": "Retrieve a specific charge"
    },
    {
      "method": "GET",
      "pathPattern": "/v1/charges/search",
      "sufficientScopes": ["charges.read"],
      "description": "Search charges"
    },
    {
      "method": "POST",
      "pathPattern": "/v1/charges",
      "sufficientScopes": ["charges.write"],
      "description": "Create a charge"
    },
    {
      "method": "POST",
      "pathPattern": "/v1/charges/*",
      "sufficientScopes": ["charges.write"],
      "description": "Update a charge"
    },
    {
      "method": "POST",
      "pathPattern": "/v1/charges/*/capture",
      "sufficientScopes": ["charges.write"],
      "description": "Capture an authorized charge"
    },
    {
      "method": "GET",
      "pathPattern": "/v1/customers",
      "sufficientScopes": ["customers.read"],
      "description": "List all customers"
    },
    {
      "method": "GET",
      "pathPattern": "/v1/customers/*",
      "sufficientScopes": ["customers.read"],
      "description": "Retrieve a specific customer"
    },
    {
      "method": "GET",
      "pathPattern": "/v1/customers/search",
      "sufficientScopes": ["customers.read"],
      "description": "Search customers"
    },
    {
      "method": "POST",
      "pathPattern": "/v1/customers",
      "sufficientScopes": ["customers.write"],
      "description": "Create a customer"
    },
    {
      "method": "POST",
      "pathPattern": "/v1/customers/*",
      "sufficientScopes": ["customers.write"],
      "description": "Update a customer"
    },
    {
      "method": "DELETE",
      "pathPattern": "/v1/customers/*",
      "sufficientScopes": ["customers.write"],
      "description": "Delete a customer"
    },
    {
      "method": "GET",
      "pathPattern": "/v1/payment_intents",
      "sufficientScopes": ["payment_intents.read"],
      "description": "List all payment intents"
    },
    {
      "method": "GET",
      "pathPattern": "/v1/payment_intents/*",
      "sufficientScopes": ["payment_intents.read"],
      "description": "Retrieve a specific payment intent"
    },
    {
      "method": "GET",
      "pathPattern": "/v1/payment_intents/search",
      "sufficientScopes": ["payment_intents.read"],
      "description": "Search payment intents"
    },
    {
      "method": "POST",
      "pathPattern": "/v1/payment_intents",
      "sufficientScopes": ["payment_intents.write"],
      "description": "Create a payment intent"
    },
    {
      "method": "POST",
      "pathPattern": "/v1/payment_intents/*",
      "sufficientScopes": ["payment_intents.write"],
      "description": "Update a payment intent"
    },
    {
      "method": "POST",
      "pathPattern": "/v1/payment_intents/*/confirm",
      "sufficientScopes": ["payment_intents.write"],
      "description": "Confirm a payment intent"
    },
    {
      "method": "POST",
      "pathPattern": "/v1/payment_intents/*/capture",
      "sufficientScopes": ["payment_intents.write"],
      "description": "Capture a payment intent"
    },
    {
      "method": "POST",
      "pathPattern": "/v1/payment_intents/*/cancel",
      "sufficientScopes": ["payment_intents.write"],
      "description": "Cancel a payment intent"
    },
    {
      "method": "POST",
      "pathPattern": "/v1/payment_intents/*/increment_authorization",
      "sufficientScopes": ["payment_intents.write"],
      "description": "Increment authorization on a payment intent"
    },
    {
      "method": "GET",
